/**
 * Per-bag mockup configuration.
 *
 * Label rect coordinates are percentages (0-100) of the bag photo dimensions.
 * isShiny enables the specular highlight pass for glossy/metallic bags.
 * warpMapDataUrl is a base64 PNG of a 256x256 canvas
 *   where R=dx, G=dy, 128=neutral (no displacement).
 * lightingMapDataUrl is a base64 PNG of a 256x256 greyscale canvas
 *   where #808080 = neutral, darker = shadow, lighter = highlight.
 */

// ─── Types ───────────────────────────────────────────────────────────

export interface Point { x: number; y: number }

export interface LabelRect {
  topLeft: Point;
  topRight: Point;
  bottomLeft: Point;
  bottomRight: Point;
}

export interface BagMockupEntry {
  labelRect: LabelRect;
  warpMapDataUrl?: string;
  lightingMapDataUrl?: string;
  lightingOpacity?: number;
  isShiny: boolean;
  labelOpacity: number;
  specularOpacity?: number;
}

