/** Fallback config for unknown bag colours */
export const DEFAULT_MOCKUP_CONFIG: BagMockupEntry = {
  labelRect: {
    topLeft: { x: 30, y: 24 },
    topRight: { x: 70, y: 24 },
    bottomLeft: { x: 28, y: 79 },
    bottomRight: { x: 72, y: 79 },
  },
  isShiny: false,
  labelOpacity: 1.0,
};

/** Look up the mockup config for a bag by name, with fallback */
export function getBagMockupConfig(bagName: string | null | undefined): BagMockupEntry {
  if (!bagName) return DEFAULT_MOCKUP_CONFIG;
  return BAG_MOCKUP_CONFIG[bagName] || DEFAULT_MOCKUP_CONFIG;
}

/** Get the boundary polygon of a label rect (4 corners) */
export function getLabelBoundary(rect: LabelRect): Point[] {
  return [rect.topLeft, rect.topRight, rect.bottomRight, rect.bottomLeft];
}

/** Size of the warp displacement map canvas */
export const WARP_MAP_SIZE = 256;

/** Create a neutral (no displacement) warp canvas */
export function createNeutralWarpCanvas(): HTMLCanvasElement {
  const canvas = document.createElement("canvas");
  canvas.width = WARP_MAP_SIZE;
  canvas.height = WARP_MAP_SIZE;
  const ctx = canvas.getContext("2d")!;
  ctx.fillStyle = "#808080";
  ctx.fillRect(0, 0, WARP_MAP_SIZE, WARP_MAP_SIZE);
  return canvas;
}

/** Size of the lighting map canvas */
export const LIGHTING_MAP_SIZE = 256;

/** Create a neutral (no effect) lighting canvas */
export function createNeutralLightingCanvas(): HTMLCanvasElement {
  const canvas = document.createElement("canvas");
  canvas.width = LIGHTING_MAP_SIZE;
  canvas.height = LIGHTING_MAP_SIZE;
  const ctx = canvas.getContext("2d")!;
  ctx.fillStyle = "#808080";
  ctx.fillRect(0, 0, LIGHTING_MAP_SIZE, LIGHTING_MAP_SIZE);
  return canvas;
}
